#nullable enable // autogenerated

using PVZEngine;

namespace MVZ2.Metas
{
    public class AlmanacVariableReferenceGlobal : AlmanacVariableReference
    {
        public NamespaceID id;

        public AlmanacVariableReferenceGlobal(NamespaceID id)
        {
            this.id = id;
        }
        public override object? GetVariableValue(AlmanacVariableContext context)
        {
            var variable = context.main.ResourceManager.GetAlmanacGlobalVariable(id);
            if (variable == null)
                return null;
            return variable.GetVariableValue(context);
        }
    }
}
